import logging
import os
from pathlib import Path

from geosat.tools.urlprotocol import UrlProtocols

_PSANP_BUNDLE_ENV_VAR = "PSANP_BUNDLE_FOLDER"

logger = logging.getLogger()

try:
    _BUNDLE_FOLDER_PATH = os.environ[_PSANP_BUNDLE_ENV_VAR]
except KeyError:
    logger.warning(
        f"The environment variable '{_PSANP_BUNDLE_ENV_VAR}' is not set, some stages may not work"
    )
    _BUNDLES = None
else:
    _BUNDLES = {Path(p).name: p for p in UrlProtocols().list(_BUNDLE_FOLDER_PATH)}


def find_in_bundle_folder(filename: str) -> str:
    if _BUNDLES is None:
        raise FileNotFoundError(
            f"The {_PSANP_BUNDLE_ENV_VAR} environment variable was not set"
        )
    try:
        return _BUNDLES[filename]
    except KeyError as exception:
        raise FileNotFoundError(
            f"File '{filename}' was not found in the bundle folder ({_BUNDLE_FOLDER_PATH})"
        ) from exception
